// ═══════════════════════════════════════════════════════════
// API KEY AUTH
// ═══════════════════════════════════════════════════════════

function authMiddleware(req, res, next) {
  const key = req.headers['x-api-key'] || req.query.key;
  if (key !== API_KEY) {
    return res.status(401).json({ error: 'Invalid API key' });
  }
  next();
}


